if (!defined('ABSPATH')) {
    exit; // Exit if accessed directly.
}

function user_file_upload_form() {
    ?>
    <div class="wrap">
        <h2>User File Upload</h2>
        <form action="" method="post" enctype="multipart/form-data">
            <?php wp_nonce_field('user_file_upload', 'user_file_upload_nonce'); ?>
            Select file to upload:
            <input type="file" name="user_file" id="user_file">
            <br><br>
            <input type="submit" value="Upload File" name="submit" class="button button-primary">
        </form>
    </div>
    <?php
}

function user_file_upload() {
    if (isset($_POST['submit']) && check_ajax_referer('user_file_upload', 'user_file_upload_nonce')) {
        $allowed_mime_types = array(
            'image/jpeg',
            'image/png',
            'application/pdf',
            'application/msword',
            'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        );

        $upload_dir = wp_upload_dir();
        $target_dir = $upload_dir['basedir'] . '/user-files/';
        if (!file_exists($target_dir)) {
            wp_mkdir_p($target_dir);
        }
        $target_file = $target_dir . basename($_FILES["user_file"]["name"]);
        $uploaded_file = move_uploaded_file($_FILES["user_file"]["tmp_name"], $target_file);

        if (in_array($_FILES['user_file']['type'], $allowed_mime_types)) {
            if ($uploaded_file) {
                echo "The file has been uploaded successfully.";
            } else {
                echo "There was an error while uploading the file.";
            }
        } else {
            echo "Invalid file type. Please choose a different file.";
        }
    }
}

add_action('admin_menu', 'user_file_upload_menu');
function user_file_upload_menu() {
    add_submenu_page('tools.php', 'User File Upload', 'User File Upload', 'manage_options', 'user-file-upload', 'user_file_upload_form');
}

add_action('wp_ajax_nopriv_user_file_upload', 'user_file_upload');
add_action('wp_ajax_user_file_upload', 'user_file_upload');